sys_script_include.script:
var AutoNumberGenerator = Class.create();
AutoNumberGenerator.prototype = {

    initialize: function() {
    },

    generate: function(tableName, fieldName, prefix) {

        var gr = new GlideRecord(tableName);
        gr.orderByDesc(fieldName);
        gr.setLimit(1);
        gr.query();

        var nextNumber = 1;

        if (gr.next()) {

            var value = gr.getValue(fieldName);

            if (value) {

                var number = parseInt(value.replace(prefix, ''), 10);

                if (!isNaN(number)) {
                    nextNumber = number + 1;
                }
            }
        }

        return prefix + ('0000' + nextNumber).slice(-4);
    },

    type: 'AutoNumberGenerator'
};
